/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 * Supports per-channel enable/disable with channel-specific configuration.
 *
 * History: Originally email-only (Session 3). Extended to multi-channel
 * (email + SMS + webhook) after SMS support was added (Session 8).
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - immediate: send as events occur
 * - daily_digest: batch into a daily summary
 * - weekly_digest: batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Base preference for any notification channel.
 */
export interface ChannelPreference {
  /** Whether this channel is enabled. */
  enabled: boolean;
}

/**
 * Email-specific channel preference.
 */
export interface EmailChannelPreference extends ChannelPreference {
  /** How often email notifications are delivered. */
  frequency: EmailFrequency;
}

/**
 * SMS-specific channel preference.
 */
export interface SmsChannelPreference extends ChannelPreference {
  /** Phone number for SMS delivery (E.164 format). */
  phoneNumber?: string;
}

/**
 * Webhook-specific channel preference.
 */
export interface WebhookChannelPreference extends ChannelPreference {
  /** Webhook URL for delivery. */
  url?: string;
}

/**
 * Per-channel preference settings.
 */
export interface ChannelPreferences {
  email: EmailChannelPreference;
  sms: SmsChannelPreference;
  webhook: WebhookChannelPreference;
}

/**
 * A user's notification preferences.
 */
export interface UserPreferences {
  /** The user this preferences record belongs to. */
  userId: string;

  /**
   * Per-channel notification settings.
   * Each channel can be independently enabled/disabled with channel-specific config.
   */
  channelPreferences: ChannelPreferences;

  /**
   * Whether email notifications are enabled at all.
   * @deprecated Use channelPreferences.email.enabled instead. Kept for backward compatibility.
   */
  emailEnabled: boolean;

  /**
   * How often email notifications are delivered.
   * @deprecated Use channelPreferences.email.frequency instead. Kept for backward compatibility.
   */
  emailFrequency: EmailFrequency;

  /** Which notification categories the user is subscribed to (shared across all channels). */
  subscribedCategories: NotificationType[];

  /** When the preferences were created. */
  createdAt: Date;
  /** When the preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 * All fields are optional -- defaults are applied by the service.
 * Supports both legacy flat fields and new channelPreferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  /** @deprecated Use channelPreferences instead. */
  emailEnabled?: boolean;
  /** @deprecated Use channelPreferences instead. */
  emailFrequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
  channelPreferences?: Partial<{
    email: Partial<EmailChannelPreference>;
    sms: Partial<SmsChannelPreference>;
    webhook: Partial<WebhookChannelPreference>;
  }>;
}

/**
 * Input for updating existing user preferences.
 * Supports both legacy flat fields and new channelPreferences.
 */
export interface UpdateUserPreferencesInput {
  /** @deprecated Use channelPreferences instead. */
  emailEnabled?: boolean;
  /** @deprecated Use channelPreferences instead. */
  emailFrequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
  channelPreferences?: Partial<{
    email: Partial<EmailChannelPreference>;
    sms: Partial<SmsChannelPreference>;
    webhook: Partial<WebhookChannelPreference>;
  }>;
}

/**
 * All notification categories -- used as the default subscription set.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'user_welcome',
  'user_updated',
];

/**
 * Default channel preferences applied when creating new user preferences.
 */
export const DEFAULT_CHANNEL_PREFERENCES: ChannelPreferences = {
  email: { enabled: true, frequency: 'immediate' },
  sms: { enabled: false },
  webhook: { enabled: false },
};

/**
 * Get whether a specific channel is enabled in the given preferences.
 */
export function isChannelEnabled(
  prefs: UserPreferences,
  channel: NotificationChannel,
): boolean {
  switch (channel) {
    case 'email':
      return prefs.channelPreferences.email.enabled;
    case 'sms':
      return prefs.channelPreferences.sms.enabled;
    case 'webhook':
      return prefs.channelPreferences.webhook.enabled;
    default:
      return false;
  }
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Keyed by userId (one preferences record per user).
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, ChannelPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { DEFAULT_CHANNEL_PREFERENCES } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences & { id: string }> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences & { id: string } {
    const emailEnabled = record['emailEnabled'] as boolean;
    const emailFrequency = record['emailFrequency'] as EmailFrequency;

    // Reconstruct channelPreferences from stored data, falling back to defaults
    const storedChannelPrefs = record['channelPreferences'] as ChannelPreferences | undefined;
    const channelPreferences: ChannelPreferences = storedChannelPrefs
      ? storedChannelPrefs
      : {
          email: { enabled: emailEnabled, frequency: emailFrequency },
          sms: { ...DEFAULT_CHANNEL_PREFERENCES.sms },
          webhook: { ...DEFAULT_CHANNEL_PREFERENCES.webhook },
        };

    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      emailEnabled,
      emailFrequency,
      channelPreferences,
      subscribedCategories: record['subscribedCategories'] as NotificationType[],
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences & { id: string }): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.emailEnabled,
      emailFrequency: entity.emailFrequency,
      channelPreferences: entity.channelPreferences,
      subscribedCategories: entity.subscribedCategories,
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): (UserPreferences & { id: string }) | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and a method to check
 * whether a notification should be sent based on the user's settings.
 * Supports per-channel preferences (email, SMS, webhook).
 *
 * Depends on:
 * - PreferencesRepository for data access
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  ChannelPreferences,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { ALL_NOTIFICATION_CATEGORIES, DEFAULT_CHANNEL_PREFERENCES } from '../models/user-preferences.js';
import { isChannelEnabled } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import { validatePreferencesNotExist, validatePreferencesExist } from '../validators/preferences.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/**
 * Reset the preferences ID counter. Used in tests.
 */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

/**
 * Build a full ChannelPreferences object from creation input, applying defaults.
 * Legacy emailEnabled/emailFrequency fields are merged with channelPreferences.email.
 */
function buildChannelPreferences(input: CreateUserPreferencesInput): ChannelPreferences {
  const emailEnabled = input.emailEnabled ?? input.channelPreferences?.email?.enabled ?? DEFAULT_CHANNEL_PREFERENCES.email.enabled;
  const emailFrequency = input.emailFrequency ?? input.channelPreferences?.email?.frequency ?? DEFAULT_CHANNEL_PREFERENCES.email.frequency;

  return {
    email: {
      enabled: emailEnabled,
      frequency: emailFrequency,
    },
    sms: {
      enabled: input.channelPreferences?.sms?.enabled ?? DEFAULT_CHANNEL_PREFERENCES.sms.enabled,
      ...(input.channelPreferences?.sms?.phoneNumber !== undefined
        ? { phoneNumber: input.channelPreferences.sms.phoneNumber }
        : {}),
    },
    webhook: {
      enabled: input.channelPreferences?.webhook?.enabled ?? DEFAULT_CHANNEL_PREFERENCES.webhook.enabled,
      ...(input.channelPreferences?.webhook?.url !== undefined
        ? { url: input.channelPreferences.webhook.url }
        : {}),
    },
  };
}

/**
 * Merge update input into existing channel preferences.
 */
function mergeChannelPreferences(
  existing: ChannelPreferences,
  input: UpdateUserPreferencesInput,
): ChannelPreferences {
  const result: ChannelPreferences = {
    email: { ...existing.email },
    sms: { ...existing.sms },
    webhook: { ...existing.webhook },
  };

  // Legacy flat fields override channelPreferences.email
  if (input.emailEnabled !== undefined) {
    result.email.enabled = input.emailEnabled;
  }
  if (input.emailFrequency !== undefined) {
    result.email.frequency = input.emailFrequency;
  }

  // channelPreferences fields (applied after legacy for explicit override)
  if (input.channelPreferences?.email) {
    if (input.channelPreferences.email.enabled !== undefined) {
      result.email.enabled = input.channelPreferences.email.enabled;
    }
    if (input.channelPreferences.email.frequency !== undefined) {
      result.email.frequency = input.channelPreferences.email.frequency;
    }
  }
  if (input.channelPreferences?.sms) {
    if (input.channelPreferences.sms.enabled !== undefined) {
      result.sms.enabled = input.channelPreferences.sms.enabled;
    }
    if (input.channelPreferences.sms.phoneNumber !== undefined) {
      result.sms = { ...result.sms, phoneNumber: input.channelPreferences.sms.phoneNumber };
    }
  }
  if (input.channelPreferences?.webhook) {
    if (input.channelPreferences.webhook.enabled !== undefined) {
      result.webhook.enabled = input.channelPreferences.webhook.enabled;
    }
    if (input.channelPreferences.webhook.url !== undefined) {
      result.webhook = { ...result.webhook, url: input.channelPreferences.webhook.url };
    }
  }

  return result;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if no preferences are set.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Create preferences for a user. Applies defaults for omitted fields.
   * Throws if preferences already exist for this user.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    validatePreferencesNotExist(existing, input.userId);

    const channelPreferences = buildChannelPreferences(input);
    const now = new Date();
    const prefs = {
      id: generatePreferencesId(),
      userId: input.userId,
      emailEnabled: channelPreferences.email.enabled,
      emailFrequency: channelPreferences.email.frequency,
      channelPreferences,
      subscribedCategories: input.subscribedCategories ?? [...ALL_NOTIFICATION_CATEGORIES],
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(prefs);
    this.logger.info(`Created preferences for user: ${input.userId}`);
    return prefs;
  }

  /**
   * Update preferences for a user. Throws if no preferences exist.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    validatePreferencesExist(existing, userId);

    const channelPreferences = mergeChannelPreferences(existing.channelPreferences, input);

    const updated = this.repository.update(existing.id, {
      ...input,
      emailEnabled: channelPreferences.email.enabled,
      emailFrequency: channelPreferences.email.frequency,
      channelPreferences,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Delete preferences for a user. Returns true if deleted, false if not found.
   */
  deletePreferences(userId: string): boolean {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      return false;
    }
    this.repository.delete(existing.id);
    this.logger.info(`Deleted preferences for user: ${userId}`);
    return true;
  }

  /**
   * Check whether a notification should be sent to a user on a given channel.
   *
   * Returns true (send) if:
   * - The user has no preferences (default: send everything on email, nothing on other channels)
   * - The channel is enabled AND the notification type is in their subscribed categories
   *
   * Returns false (suppress) if:
   * - The channel is disabled
   * - The notification type is not in their subscribed categories
   *
   * @param userId - The user to check
   * @param notificationType - The notification category
   * @param channel - The delivery channel (defaults to 'email' for backward compatibility)
   */
  shouldSendNotification(
    userId: string,
    notificationType: NotificationType,
    channel: NotificationChannel = 'email',
  ): boolean {
    const prefs = this.repository.findByUserId(userId);

    // No preferences -> default: send on email only, suppress other channels
    if (!prefs) {
      return channel === 'email';
    }

    // Channel toggle
    if (!isChannelEnabled(prefs, channel)) {
      return false;
    }

    // Category check
    return prefs.subscribedCategories.includes(notificationType);
  }

  /**
   * Get or create preferences for a user (upsert with defaults).
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createPreferences({ userId });
  }
}

