import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import { SmsNotificationAdapter } from '../../src/adapters/sms.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('immediate');
      expect(prefs.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'user_welcome',
        'user_updated',
      ]);
      expect(prefs.createdAt).toBeInstanceOf(Date);
      expect(prefs.updatedAt).toBeInstanceOf(Date);

      // Multi-channel defaults
      expect(prefs.channelPreferences.email.enabled).toBe(true);
      expect(prefs.channelPreferences.email.frequency).toBe('immediate');
      expect(prefs.channelPreferences.sms.enabled).toBe(false);
      expect(prefs.channelPreferences.webhook.enabled).toBe(false);
    });

    it('should create preferences with custom values', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
        emailFrequency: 'daily_digest',
        subscribedCategories: ['order_confirmation'],
      });

      expect(prefs.emailEnabled).toBe(false);
      expect(prefs.emailFrequency).toBe('daily_digest');
      expect(prefs.subscribedCategories).toEqual(['order_confirmation']);
      expect(prefs.channelPreferences.email.enabled).toBe(false);
      expect(prefs.channelPreferences.email.frequency).toBe('daily_digest');
    });

    it('should create preferences with channelPreferences input', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        channelPreferences: {
          email: { enabled: true, frequency: 'weekly_digest' },
          sms: { enabled: true, phoneNumber: '+15551234567' },
          webhook: { enabled: true, url: 'https://example.com/hook' },
        },
      });

      expect(prefs.channelPreferences.email.enabled).toBe(true);
      expect(prefs.channelPreferences.email.frequency).toBe('weekly_digest');
      expect(prefs.channelPreferences.sms.enabled).toBe(true);
      expect(prefs.channelPreferences.sms.phoneNumber).toBe('+15551234567');
      expect(prefs.channelPreferences.webhook.enabled).toBe(true);
      expect(prefs.channelPreferences.webhook.url).toBe('https://example.com/hook');
      // Legacy fields synced
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('weekly_digest');
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });
  });

  describe('getPreferences', () => {
    it('should return undefined for unknown user', () => {
      expect(service.getPreferences('nonexistent')).toBeUndefined();
    });

    it('should return preferences for a known user', () => {
      service.createPreferences({ userId: 'user-1' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled flag', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', { emailEnabled: false });
      expect(updated.emailEnabled).toBe(false);
      expect(updated.channelPreferences.email.enabled).toBe(false);
    });

    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        emailFrequency: 'weekly_digest',
      });
      expect(updated.emailFrequency).toBe('weekly_digest');
      expect(updated.channelPreferences.email.frequency).toBe('weekly_digest');
    });

    it('should update subscribed categories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });
      expect(updated.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should update SMS channel preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        channelPreferences: {
          sms: { enabled: true, phoneNumber: '+15559876543' },
        },
      });
      expect(updated.channelPreferences.sms.enabled).toBe(true);
      expect(updated.channelPreferences.sms.phoneNumber).toBe('+15559876543');
      // Email unchanged
      expect(updated.channelPreferences.email.enabled).toBe(true);
    });

    it('should update webhook channel preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        channelPreferences: {
          webhook: { enabled: true, url: 'https://example.com/hook' },
        },
      });
      expect(updated.channelPreferences.webhook.enabled).toBe(true);
      expect(updated.channelPreferences.webhook.url).toBe('https://example.com/hook');
    });

    it('should throw if no preferences exist for user', () => {
      expect(() =>
        service.updatePreferences('nonexistent', { emailEnabled: false }),
      ).toThrow('No preferences found for user: nonexistent');
    });

    it('should update the updatedAt timestamp', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });
      const originalUpdatedAt = prefs.updatedAt;

      const updated = service.updatePreferences('user-1', { emailEnabled: false });
      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(
        originalUpdatedAt.getTime(),
      );
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false for nonexistent user', () => {
      expect(service.deletePreferences('nonexistent')).toBe(false);
    });
  });

  describe('shouldSendNotification', () => {
    it('should return true when no preferences exist (default behavior for email)', () => {
      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when no preferences exist for non-email channel', () => {
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'webhook')).toBe(false);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendNotification('user-1', 'user_welcome')).toBe(false);
    });

    it('should return true for subscribed category even with limited subscription', () => {
      service.createPreferences({
        userId: 'user-1',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email disabled regardless of categories', () => {
      service.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
        subscribedCategories: ['order_confirmation', 'order_status_update', 'user_welcome', 'user_updated'],
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });

    it('should check SMS channel preferences correctly', () => {
      service.createPreferences({
        userId: 'user-1',
        channelPreferences: {
          sms: { enabled: true, phoneNumber: '+15551234567' },
        },
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'email')).toBe(true);
    });

    it('should return false for disabled SMS channel', () => {
      service.createPreferences({ userId: 'user-1' });
      // SMS is disabled by default
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(false);
    });

    it('should check webhook channel preferences correctly', () => {
      service.createPreferences({
        userId: 'user-1',
        channelPreferences: {
          webhook: { enabled: true, url: 'https://example.com/hook' },
        },
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'webhook')).toBe(true);
    });

    it('should respect category filter across all channels', () => {
      service.createPreferences({
        userId: 'user-1',
        subscribedCategories: ['order_confirmation'],
        channelPreferences: {
          sms: { enabled: true },
          webhook: { enabled: true },
        },
      });

      // Subscribed category
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'email')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'webhook')).toBe(true);

      // Unsubscribed category
      expect(service.shouldSendNotification('user-1', 'user_welcome', 'email')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'user_welcome', 'sms')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'user_welcome', 'webhook')).toBe(false);
