describe('NotificationService with multi-channel preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailAdapter: EmailNotificationAdapter;
  let smsAdapter: SmsNotificationAdapter;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailNotificationAdapter();
    smsAdapter = new SmsNotificationAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);

    const repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should send via SMS when SMS is enabled and notification sent on SMS channel', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      channelPreferences: {
        sms: { enabled: true, phoneNumber: '+15551234567' },
      },
    });

    await notificationService.send({
      type: 'order_confirmation',
      recipient: '+15551234567',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed.',
      channel: 'sms',
      userId: 'user-1',
    });

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(notificationService.getNotifications()[0]?.channel).toBe('sms');
  });

  it('should suppress SMS when SMS is disabled in preferences', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      // SMS disabled by default
    });

    const result = await notificationService.send({
      type: 'order_confirmation',
      recipient: '+15551234567',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed.',
      channel: 'sms',
      userId: 'user-1',
    });

    expect(result).toBeUndefined();
    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should allow email while suppressing SMS for same user', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      // Email enabled by default, SMS disabled by default
    });

    // Email should work
    await notificationService.send({
      type: 'order_confirmation',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed.',
      channel: 'email',
      userId: 'user-1',
    });

    // SMS should be suppressed
    await notificationService.send({
      type: 'order_confirmation',
      recipient: '+15551234567',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed.',
      channel: 'sms',
      userId: 'user-1',
    });

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(notificationService.getNotifications()[0]?.channel).toBe('email');
  });

  it('should send on both email and SMS when both are enabled', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      channelPreferences: {
        email: { enabled: true, frequency: 'immediate' },
        sms: { enabled: true, phoneNumber: '+15551234567' },
      },
    });

    await notificationService.send({
      type: 'order_confirmation',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed.',
      channel: 'email',
      userId: 'user-1',
    });

    await notificationService.send({
      type: 'order_confirmation',
      recipient: '+15551234567',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed.',
      channel: 'sms',
      userId: 'user-1',
    });

    expect(notificationService.getNotificationCount()).toBe(2);
  });

  it('should suppress non-email channels when user has no preferences', async () => {
    // No preferences set — default is email-only
    const result = await notificationService.send({
      type: 'order_confirmation',
      recipient: '+15551234567',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed.',
      channel: 'sms',
      userId: 'user-1',
    });

